patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index f76e913a57d5..151bbd572788 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -2736,8 +2736,10 @@ public:
             wouldInstructionBeTriviallyDead(OpI, TLI) &&
             (Entries.empty() || none_of(Entries, [&](const TreeEntry *Entry) {
                return Entry->VectorizedValue == OpI;
-             })))
+             }))) {
           DeadInsts.push_back(OpI);
+          DeletedInstructions.insert(OpI);
+        }
       }
       I->dropAllReferences();
     }
@@ -2747,8 +2749,11 @@ public:
         continue;
       assert((I->use_empty() || all_of(I->uses(),
                                        [&](Use &U) {
-                                         return isDeleted(
-                                             cast<Instruction>(U.getUser()));
+                                         auto *UserI = cast<Instruction>(U.getUser());
+                                         if (!isDeleted(UserI)) {
+                                           DeletedInstructions.insert(UserI);
+                                         }
+                                         return isDeleted(UserI);
                                        })) &&
              "trying to erase instruction with users.");
       I->removeFromParent();

